#include <ArduinoJson.h>

// Pin Configuration
#define MQ135_PIN {{.mq135Pin}}
#define RED_LED_PIN {{.redLedPin}}
#define YELLOW_LED_PIN {{.yellowLedPin}}
#define GREEN_LED_PIN {{.greenLedPin}}
#define BUZZER_PIN {{.buzzerPin}}

// Threshold Configuration
#define POOR_THRESHOLD {{.poorThreshold}} // AQI > this = Poor
#define MODERATE_THRESHOLD {{.moderateThreshold}} // AQI > this = Moderate
#define READING_INTERVAL {{.readingInterval}} // Seconds between readings

// Sensor Calibration
#define CLEAN_AIR_VALUE {{.sensorCalibrationClean}} // Analog reading in clean air
#define POLLUTED_AIR_VALUE {{.sensorCalibrationPolluted}} // Analog reading in polluted air

// Configuration
#define ENABLE_LOGGING {{.enableLogging}}
#define ENABLE_ALERTS {{.enableAlerts}}

// Air Quality Categories
enum AirQuality {
  GOOD,
  MODERATE,
  POOR,
  VERY_POOR
};

// Global variables
AirQuality current_quality = GOOD;
unsigned long last_reading_time = 0;
int current_aqi = 0;
int raw_sensor_value = 0;
float temperature = 25.0; // Assume room temperature for simplicity
float humidity = 50.0; // Assume 50% humidity

// Statistics
int aqi_history[24]; // Store last 24 readings (4 hours at 10min intervals)
int history_index = 0;
int aqi_sum = 0;
int aqi_max = 0;
int aqi_min = 500;
unsigned long alert_start_time = 0;
bool continuous_alert = false;

// Function prototypes
int read_mq135();
int calculate_aqi(int raw_value);
AirQuality get_air_quality_category(int aqi);
void update_leds(AirQuality quality);
void handle_alerts(AirQuality quality);
void log_data();
void update_statistics();
void beep_alert(int duration_ms);

void setup() {
  Serial.begin(115200);
  Serial.println("Air Quality Sensor with LED Indicator and Logging Starting...");

  // Initialize pins
  pinMode(MQ135_PIN, INPUT);
  pinMode(RED_LED_PIN, OUTPUT);
  pinMode(YELLOW_LED_PIN, OUTPUT);
  pinMode(GREEN_LED_PIN, OUTPUT);

  if (BUZZER_PIN > 0) {
    pinMode(BUZZER_PIN, OUTPUT);
  }

  // Initialize all LEDs OFF
  digitalWrite(RED_LED_PIN, LOW);
  digitalWrite(YELLOW_LED_PIN, LOW);
  digitalWrite(GREEN_LED_PIN, LOW);

  if (BUZZER_PIN > 0) {
    digitalWrite(BUZZER_PIN, LOW);
  }

  // Initialize AQI history
  for (int i = 0; i < 24; i++) {
    aqi_history[i] = 0;
  }

  // Wait for sensor to warm up (MQ-135 needs warm-up time)
  Serial.println("Warming up sensor...");
  for (int i = 0; i < 60; i++) { // 60 seconds warm-up
    delay(1000);
    Serial.print(".");
  }
  Serial.println("\nSensor ready!");

  // Take initial reading
  current_aqi = calculate_aqi(read_mq135());
  aqi_history[0] = current_aqi;
  current_quality = get_air_quality_category(current_aqi);
  update_leds(current_quality);

  // Print configuration
  Serial.print("Configuration:");
  Serial.print(" Poor Threshold: ");
  Serial.print(POOR_THRESHOLD);
  Serial.print(", Moderate Threshold: ");
  Serial.print(MODERATE_THRESHOLD);
  Serial.print(", Reading Interval: ");
  Serial.print(READING_INTERVAL);
  Serial.println("s");

  Serial.print("Calibration - Clean: ");
  Serial.print(CLEAN_AIR_VALUE);
  Serial.print(", Polluted: ");
  Serial.println(POLLUTED_AIR_VALUE);

  Serial.print("Initial AQI: ");
  Serial.print(current_aqi);
  Serial.print(", Quality: ");
  Serial.println(get_quality_string(current_quality));
}

void loop() {
  unsigned long current_time = millis();

  // Take reading at specified interval
  if (current_time - last_reading_time >= (READING_INTERVAL * 1000UL)) {
    last_reading_time = current_time;

    // Read sensor
    raw_sensor_value = read_mq135();
    current_aqi = calculate_aqi(raw_sensor_value);
    current_quality = get_air_quality_category(current_aqi);

    // Update history and statistics
    aqi_history[history_index] = current_aqi;
    history_index = (history_index + 1) % 24;
    update_statistics();

    // Update indicators
    if (ENABLE_ALERTS) {
      update_leds(current_quality);
      handle_alerts(current_quality);
    }

    // Log data
    if (ENABLE_LOGGING) {
      log_data();
    }
  }

  delay(100); // Small delay
}

int read_mq135() {
  // Take multiple readings and average for stability
  long sum = 0;
  int readings = 10;

  for (int i = 0; i < readings; i++) {
    sum += analogRead(MQ135_PIN);
    delay(10);
  }

  return sum / readings;
}

int calculate_aqi(int raw_value) {
  // Map raw sensor value to AQI (0-500 scale)
  // This is a simplified calculation - real AQI calculation is more complex
  int aqi = map(raw_value, CLEAN_AIR_VALUE, POLLUTED_AIR_VALUE, 0, 500);

  // Constrain to valid range
  if (aqi < 0) aqi = 0;
  if (aqi > 500) aqi = 500;

  return aqi;
}

AirQuality get_air_quality_category(int aqi) {
  if (aqi >= POOR_THRESHOLD) {
    return POOR;
  } else if (aqi >= MODERATE_THRESHOLD) {
    return MODERATE;
  } else {
    return GOOD;
  }
}

const char* get_quality_string(AirQuality quality) {
  switch (quality) {
    case GOOD: return "Good";
    case MODERATE: return "Moderate";
    case POOR: return "Poor";
    case VERY_POOR: return "Very Poor";
    default: return "Unknown";
  }
}

void update_leds(AirQuality quality) {
  // Turn all LEDs off first
  digitalWrite(RED_LED_PIN, LOW);
  digitalWrite(YELLOW_LED_PIN, LOW);
  digitalWrite(GREEN_LED_PIN, LOW);

  // Turn on appropriate LED
  switch (quality) {
    case GOOD:
      digitalWrite(GREEN_LED_PIN, HIGH);
      break;
    case MODERATE:
      digitalWrite(YELLOW_LED_PIN, HIGH);
      break;
    case POOR:
    case VERY_POOR:
      digitalWrite(RED_LED_PIN, HIGH);
      break;
  }
}

void handle_alerts(AirQuality quality) {
  static unsigned long last_buzz_time = 0;
  unsigned long current_time = millis();

  if (quality == POOR || quality == VERY_POOR) {
    if (!continuous_alert) {
      // Start continuous alert
      continuous_alert = true;
      alert_start_time = current_time;

      if (BUZZER_PIN > 0) {
        beep_alert(500); // Initial alert
      }
    } else {
      // Periodic buzzing during continuous alert
      if (BUZZER_PIN > 0 && (current_time - last_buzz_time >= 5000)) {
        beep_alert(200);
        last_buzz_time = current_time;
      }
    }
  } else {
    // Reset alert when air quality improves
    if (continuous_alert) {
      continuous_alert = false;
      if (BUZZER_PIN > 0) {
        digitalWrite(BUZZER_PIN, LOW);
      }
    }
  }
}

void log_data() {
  // Create detailed JSON log entry
  StaticJsonDocument<300> doc;
  doc["timestamp"] = millis();
  doc["aqi"] = current_aqi;
  doc["quality"] = get_quality_string(current_quality);
  doc["raw_sensor"] = raw_sensor_value;
  doc["temperature"] = temperature;
  doc["humidity"] = humidity;
  doc["aqi_min"] = aqi_min;
  doc["aqi_max"] = aqi_max;
  doc["aqi_avg"] = (history_index > 0) ? (aqi_sum / min(history_index, 24)) : current_aqi;
  doc["alert_active"] = continuous_alert;

  // Serialize and output
  String json_string;
  serializeJson(doc, json_string);
  Serial.println(json_string);

  // Also output human-readable summary
  Serial.print("AQI: ");
  Serial.print(current_aqi);
  Serial.print(" (");
  Serial.print(get_quality_string(current_quality));
  Serial.print(") - Raw: ");
  Serial.print(raw_sensor_value);
  Serial.print(" - Min: ");
  Serial.print(aqi_min);
  Serial.print(", Max: ");
  Serial.print(aqi_max);
  Serial.print(", Avg: ");
  Serial.print((history_index > 0) ? (aqi_sum / min(history_index, 24)) : current_aqi);
  if (continuous_alert) {
    Serial.print(" [ALERT]");
  }
  Serial.println();
}

void update_statistics() {
  // Calculate min, max, and sum from history
  aqi_sum = 0;
  aqi_max = 0;
  aqi_min = 500;

  int count = min(history_index, 24);
  if (count == 0) return;

  for (int i = 0; i < count; i++) {
    int value = aqi_history[i];
    if (value > 0) { // Ignore uninitialized values
      aqi_sum += value;
      if (value > aqi_max) aqi_max = value;
      if (value < aqi_min) aqi_min = value;
    }
  }
}

void beep_alert(int duration_ms) {
  if (BUZZER_PIN > 0) {
    digitalWrite(BUZZER_PIN, HIGH);
    delay(duration_ms);
    digitalWrite(BUZZER_PIN, LOW);
  }
}
